// ═══════════════════════════════════════════════════════════
// RAG KNOWLEDGE BASE — Gadget & More Electronics
// Source of truth: snippets/knowledge-base.md
// To add a new document: append new chunk objects to KB below
// ═══════════════════════════════════════════════════════════

const KB = [
  {
    topic: 'shipping',
    keywords: ['ship', 'shipping', 'delivery', 'deliver', 'track', 'arrive', 'standard', 'express', 'days', 'po box', 'military'],
    text: 'SHIPPING & DELIVERY: Standard 3-7 business days (free on orders $99+). Express 1-3 business days (extra fee at checkout). Ships to all US states, PO Boxes, and military addresses. Tracking emailed within 24 hours of shipment.'
  },
  {
    topic: 'returns',
    keywords: ['return', 'refund', 'send back', 'exchange', 'defective', 'damaged', 'wrong item', 'restocking', 'money back', '30 day', 'change of mind'],
    text: 'RETURNS & REFUNDS: 30-day return window from delivery date. Items must be in original condition (opened OK if defective). Free return shipping for wrong, defective, or damaged items. Customer pays return shipping for change-of-mind returns. Refunds to original payment method in 5-10 business days. 15% restocking fee may apply on non-defective returns.'
  },
  {
    topic: 'warranty',
    keywords: ['warranty', 'guarantee', 'broken', 'defect', 'manufacturer', 'replace', 'refurbished', 'open-box', 'open box', '1 year', '90 day'],
    text: 'WARRANTY: New items: 1-year manufacturer warranty + 30-day GadgetHub replacement guarantee. Refurbished/open-box items: 90-day GadgetHub warranty only. Physical damage or misuse voids the warranty.'
  },
  {
    topic: 'repairs',
    keywords: ['repair', 'fix', 'broken', 'not working', 'malfunction', 'service', 'technician', 'damage', 'stopped working'],
    text: 'REPAIRS: Warranty covers manufacturer defects only — not physical damage or misuse. Contact us within the warranty period for repair or replacement options.'
  },
  {
    topic: 'billing',
    keywords: ['charge', 'charged', 'billing', 'duplicate', 'payment', 'rewards', 'membership', 'subscription', 'cancel', 'renew', '9.99', 'prorated'],
    text: 'BILLING & SUBSCRIPTIONS: GadgetHub Rewards costs $9.99/month, cancel anytime. Prorated refunds available only within 14 days of renewal. Duplicate charges refunded within 48 hours.'
  },
  {
    topic: 'pricing',
    keywords: ['price', 'promo', 'discount', 'coupon', 'code', 'promotion', 'match', 'combine', 'gift card'],
    text: 'PRICING & PROMOTIONS: No price matching after purchase. Promo codes and gift cards usually cannot be combined.'
  },
  {
    topic: 'gift_cards',
    keywords: ['gift card', 'gift', 'card', 'balance', 'invalid', 'expire', 'redeem', 'voucher'],
    text: 'GIFT CARDS: Never expire, no cash value. Check code/balance in your account. Contact us with a screenshot if the card is still showing as invalid.'
  },
  {
    topic: 'privacy',
    keywords: ['privacy', 'data', 'personal', 'sell', 'share', 'information', 'gdpr', 'info'],
    text: 'PRIVACY: We do not sell your personal data. Limited sharing with carriers and payment processors only.'
  }
];

// Extract email fields from Gmail Trigger output
const email = $input.first().json;
const emailId   = email.id        || '';
const threadId  = email.threadId  || '';
const from      = email.from      || '';
const subject   = email.subject   || '(no subject)';
const body      = email.text      || email.snippet || email.html || '';

// ── RAG: keyword-based retrieval ────────────────────────────────────
const searchText = (subject + ' ' + body).toLowerCase();
const matched = KB.filter(chunk =>
  chunk.keywords.some(kw => searchText.includes(kw))
);
// Fall back to entire KB if no keywords matched
const retrieved = matched.length > 0 ? matched : KB;
const context = retrieved.map(c => c.text).join('\n\n');

// ── Build prompt strings ──────────────────────────────────────────
const systemPrompt =
`You are a helpful customer support agent for Gadget & More Electronics.
Use ONLY the following retrieved knowledge base to answer. Do not invent details.

KNOWLEDGE BASE:
${context}

You MUST respond with ONLY valid JSON and nothing else — no markdown, no code fences, no extra text.
Use this exact format:
{"category":"returns|warranty|repairs|billing|shipping|pricing|gift_cards|privacy|other","is_relevant":true,"draft_response":"full reply text"}

Rules:
- Set is_relevant to false for spam, newsletters, sales emails, or anything unrelated to Gadget & More Electronics customer support.
- If is_relevant is false, set draft_response to an empty string.
- Keep the tone professional, warm, and concise.
- Sign off as: Gadget & More Electronics Customer Support Team`;

const userMessage = `From: ${from}\nSubject: ${subject}\n\n${body}`;

return [{
  json: { emailId, threadId, from, subject, systemPrompt, userMessage }
}];

const r = $input.first().json;
const e = $('Extract & Search KB').first().json;

// Native OpenAI node with simplifyOutput:false → choices[0].message.content
const content = r.choices?.[0]?.message?.content || '';

let ai = { category: 'other', is_relevant: false, draft_response: '' };
try {
  // Try direct parse first
  ai = JSON.parse(content);
} catch(ex) {
  // Extract JSON from potential markdown code blocks
  const block = content.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  const bare  = content.match(/\{[\s\S]*\}/);
  const raw   = block ? block[1] : bare ? bare[0] : null;
  if (raw) { try { ai = JSON.parse(raw); } catch(ex2) {} }
}

return [{ json: {
  emailId:        e.emailId,
  threadId:       e.threadId,
  from:           e.from,
  subject:        e.subject,
  category:       ai.category || 'other',
  is_relevant:    ai.is_relevant === true,
  draft_response: ai.draft_response || ''
} }];

