const symbol = $input.first().json.symbol;
const currentPrice = $input.first().json.currentPrice;
const fiftyTwoWeekHigh = $input.first().json["52WeekHigh"];

// Calculate percentage discount from 52-week high
const discount = ((fiftyTwoWeekHigh - currentPrice) / fiftyTwoWeekHigh) * 100;

// Round to 2 decimal places
const discountPercentage = Math.round(discount * 100) / 100;

// Get today's date in New Zealand format (dd-mm-yyyy)
const today = new Date().toLocaleDateString('en-NZ').replace(/\//g, '-');

// Return the result
return [{
  json: {
    date: today,
    symbol,
    currentPrice: currentPrice,
    fiftyTwoWeekHigh: fiftyTwoWeekHigh,
    discountPercentage: discountPercentage,
    discountAmount: fiftyTwoWeekHigh - currentPrice
  }
}];

