return items.map(item => {
  const d = item.json;

  // Use the email's internalDate (ms epoch) or fall back to the Date header
  const emailDate = d.internalDate
    ? new Date(parseInt(d.internalDate))
    : new Date(d.date ?? d.Date ?? Date.now());

  const pad = n => String(n).padStart(2, '0');
  const timestamp = `${emailDate.getFullYear()}-${pad(emailDate.getMonth()+1)}-${pad(emailDate.getDate())} ${pad(emailDate.getHours())}:${pad(emailDate.getMinutes())}`;

  return {
    json: {
      "Timestamp": timestamp,
      "From": d.from?.value?.[0]?.address ?? d.From ?? "",
      "Subject": d.subject ?? d.Subject ?? "",
      "Body Snippet": (d.snippet ?? "").substring(0, 200)
