// N8N JavaScript Code Node - Convert AI Agent Output to Supabase blogs_rows format
// This handles the blog content from Google Sheets and transforms it to match your Supabase schema

const generateUUID = () => {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

const extractMarkdownHeading = (content) => {
  const match = content.match(/^#+\s+(.+?)(?:\n|$)/m);
  return match ? match[1].trim() : "Untitled Blog Post";
};

const createSlug = (title) => {
  return title
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
};

const extractExcerpt = (content, length = 200) => {
  const cleanText = content
    .replace(/^#+\s+/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .replace(/`(.+?)`/g, '$1')
    .replace(/\[(.+?)\]\(.+?\)/g, '$1')
    .replace(/#+\s+/g, '')
    .replace(/\n\n+/g, ' ')
    .trim();

  return cleanText.substring(0, length) + '...';
};

const extractTags = (content, blogTopic = '') => {
  const tags = [];
  const lowerContent = content.toLowerCase();

  // Auto-detect tags from content
  if (lowerContent.includes('prompt')) tags.push('prompt engineering');
  if (lowerContent.includes('generative ai') || lowerContent.includes('generative')) tags.push('generative AI');
  if (lowerContent.includes('ai') || lowerContent.includes('artificial intelligence')) tags.push('artificial intelligence');
  if (lowerContent.includes('llm') || lowerContent.includes('language model')) tags.push('large language models');
  if (lowerContent.includes('gpt')) tags.push('GPT');
  if (lowerContent.includes('technique')) tags.push('AI techniques');
  if (lowerContent.includes('best practice')) tags.push('best practices');
  if (lowerContent.includes('application')) tags.push('AI applications');
  if (lowerContent.includes('tutorial')) tags.push('tutorial');

  // Add blog topic if provided
  if (blogTopic && !tags.includes(blogTopic)) {
    tags.push(blogTopic);
  }

  return tags.length > 0 ? tags : ["AI", "content"];
};

// Process each input item
for (const item of $input.all()) {
  try {
    const blogContent = item.json.Blog || item.json.output || '';
    const blogTopic = item.json['Blog Topic'] || 'AI Content';

    if (!blogContent) {
      console.error('No blog content found in item');
      continue;
    }

    const title = extractMarkdownHeading(blogContent);
    const slug = createSlug(title);
    const excerpt = extractExcerpt(blogContent, 200);
    const tags = extractTags(blogContent, blogTopic);

    // Extract first 150 chars for subtitle
    const cleanForSubtitle = blogContent
      .replace(/^#+\s+/gm, '')
      .replace(/[\*_`\[\]]/g, '')
      .split('\n')[1]?.trim() || title;
    const subtitle = cleanForSubtitle.substring(0, 150);

    // Create SEO keywords
    const seoKeywords = [
      title,
      ...tags,
      `${title} tutorial`,
      `how to ${title.toLowerCase()}`,
      blogTopic
    ];

    // Transform to Supabase schema
    item.json = {
      // Core fields
      id: generateUUID(),
      idx: Math.floor(Math.random() * 10000),

      // Content fields
      title: title,
      subtitle: subtitle,
      slug: slug,
      content: blogContent,
      excerpt: excerpt,

      // Media
      featured_image: "https://qzmttorvdvelptscboqp.supabase.co/storage/v1/object/public/projects/default-blog-image.jpeg",

      // Category
      category_id: null,
      category_ids: [],

      // Publisher info (from N8N/AI Agent)
      publisher_name: "AI Agent",
      publisher_image: "https://qzmttorvdvelptscboqp.supabase.co/storage/v1/object/public/publisher-images/default-agent.jpg",
      publisher_twitter: null,
      publisher_linkedin: null,
      publisher_github: null,
      publisher_website: null,
      publisher_instagram: null,
      publisher_facebook: null,

      // SEO fields
      tags: tags,
      seo_title: `${title} | MyDesign Nexus Blog`,
      seo_description: excerpt,
      seo_keywords: seoKeywords,

      // Status & timestamps
      status: "published",
      published_at: new Date().toISOString(),
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),

      // Author & Publisher IDs
      author_id: generateUUID(),
      publisher_id: generateUUID(),

      // Analytics
      views_count: 0
    };

  } catch (error) {
    console.error(`Error processing item: ${error.message}`);
    item.json.error = error.message;
  }
}

return $input.all();

