const destinationPath = folderPath + outputFileName;

// Split into lines
const lines = fileContent.split('\n');

// Keep the header row
const header = lines[0];

// Process data rows (skip header)
const validLines = lines.slice(1).filter(line => {
  if (!line.trim()) return false;

  const columns = line.split('|');
  const dob = columns[5];

  return isValidDate(dob);
});

function isValidDate(dateString) {
  if (!dateString || !dateString.trim()) return false;

  const parts = dateString.split('-');
  if (parts.length !== 3) return false;

  const month = parseInt(parts[0], 10);
  const day = parseInt(parts[1], 10);
  const year = parseInt(parts[2], 10);

  if (isNaN(month) || isNaN(day) || isNaN(year)) return false;
  if (month < 1 || month > 12) return false;
  if (day < 1 || day > 31) return false;
  if (year < 1900 || year > 2100) return false;

  const date = new Date(year, month - 1, day);
  return date.getFullYear() === year && 
         date.getMonth() === month - 1 && 
         date.getDate() === day;
}

// Reconstruct the cleaned file
const cleanedFile = [header, ...validLines].join('\n');

// Return with path in JSON for the FTP node
return [{
  json: {
    path: destinationPath
  },
  binary: {
    data: await this.helpers.prepareBinaryData(
      Buffer.from(cleanedFile, 'utf-8'),
      outputFileName,
      'text/plain'
    )
  }
}];

