// Get all input items from the merged data
const items = $input.all();

// Initialize variables to store data from both PDF Vector nodes
let contractData = null;
let riskAnalysis = null;

// Process each item to find the extraction and risk analysis results
items.forEach(item => {
  // Check if this item contains extraction data (has 'data' property)
  if (item.json && item.json.data) {
    contractData = item.json.data;
  }

  // Check if this item contains risk analysis (has 'answer' property)
  if (item.json && item.json.answer) {
    riskAnalysis = item.json.answer;
  }
});

// Validate that we received contract data
if (!contractData) {
  throw new Error('Contract extraction data not found. Ensure PDF Vector - Extract Contract node is working correctly.');
}

// Risk analysis is optional - set default if not found
if (!riskAnalysis) {
  riskAnalysis = "Risk analysis not available - manual review recommended.";
}

// Calculate contract duration and dates
const today = new Date();
let effectiveDate = null;
let expirationDate = null;
let daysUntilExpiration = null;
let contractDuration = null;

// Safely parse dates
try {
  if (contractData.effectiveDate) {
    effectiveDate = new Date(contractData.effectiveDate);
  }
  if (contractData.expirationDate) {
    expirationDate = new Date(contractData.expirationDate);
  }

  if (expirationDate && effectiveDate) {
    // Calculate days until expiration from today
    daysUntilExpiration = Math.floor((expirationDate - today) / (1000 * 60 * 60 * 24));
    // Calculate total contract duration
    contractDuration = Math.floor((expirationDate - effectiveDate) / (1000 * 60 * 60 * 24));
  }
} catch (error) {
  console.error('Error parsing dates:', error);
}

// Process deliverables and create timeline
const upcomingDeliverables = [];
const overdueDeliverables = [];

if (contractData.deliverables && Array.isArray(contractData.deliverables)) {
  contractData.deliverables.forEach((deliverable, index) => {
    try {
      if (deliverable.dueDate) {
        const dueDate = new Date(deliverable.dueDate);
        const daysUntilDue = Math.floor((dueDate - today) / (1000 * 60 * 60 * 24));

        const deliverableInfo = {
          ...deliverable,
          dueDate: dueDate.toISOString().split('T')[0],
          daysUntilDue: daysUntilDue,
          status: daysUntilDue < 0 ? 'Overdue' : daysUntilDue <= 7 ? 'Urgent' : daysUntilDue <= 30 ? 'Upcoming' : 'Future'
        };

        if (daysUntilDue < 0) {
          overdueDeliverables.push(deliverableInfo);
        } else {
          upcomingDeliverables.push(deliverableInfo);
        }
      }
    } catch (error) {
      console.error(`Error processing deliverable ${index}:`, error);
    }
  });
}

// Sort deliverables by due date
upcomingDeliverables.sort((a, b) => a.daysUntilDue - b.daysUntilDue);
overdueDeliverables.sort((a, b) => b.daysUntilDue - a.daysUntilDue);

// Process obligations
const obligationsByParty = {};
if (contractData.obligations && Array.isArray(contractData.obligations)) {
  contractData.obligations.forEach(obligation => {
    const party = obligation.party || 'Unknown Party';
    if (!obligationsByParty[party]) {
      obligationsByParty[party] = [];
    }
    obligationsByParty[party].push(obligation);
  });
}

// Create compliance checklist
const complianceChecklist = [];

// Check parties
complianceChecklist.push({
  item: 'Parties Identification',
  status: contractData.parties && contractData.parties.length >= 2 ? 'Complete' : 'Missing',
  details: contractData.parties ? `${contractData.parties.length} parties identified` : 'No parties found',
  required: true,
  severity: 'Critical'
});

// Check payment terms
complianceChecklist.push({
  item: 'Payment Terms',
  status: contractData.paymentTerms && contractData.paymentTerms.amount ? 'Complete' : 'Missing',
  details: contractData.paymentTerms?.amount ? `Amount: ${contractData.paymentTerms.amount}` : 'Payment amount not specified',
  required: true,
  severity: 'High'
});

// Check dates
complianceChecklist.push({
  item: 'Contract Duration',
  status: effectiveDate && expirationDate ? 'Complete' : 'Missing',
  details: effectiveDate && expirationDate ? `${contractDuration} days (${contractData.effectiveDate} to ${contractData.expirationDate})` : 'Contract dates not specified',
  required: true,
  severity: 'High'
});

// Check termination clauses
complianceChecklist.push({
  item: 'Termination Clauses',
  status: contractData.terminationClauses && contractData.terminationClauses.length > 0 ? 'Complete' : 'Missing',
  details: contractData.terminationClauses ? `${contractData.terminationClauses.length} termination clauses found` : 'No termination clauses',
  required: true,
  severity: 'High'
});

// Check governing law
complianceChecklist.push({
  item: 'Governing Law',
  status: contractData.governingLaw ? 'Complete' : 'Missing',
  details: contractData.governingLaw || 'Governing law not specified',
  required: true,
  severity: 'Medium'
});

// Check dispute resolution
complianceChecklist.push({
  item: 'Dispute Resolution',
  status: contractData.disputeResolution ? 'Complete' : 'Missing',
  details: contractData.disputeResolution || 'Dispute resolution not specified',
  required: false,
  severity: 'Low'
});

// Calculate compliance score
const totalRequired = complianceChecklist.filter(item => item.required).length;
const completedRequired = complianceChecklist.filter(item => item.required && item.status === 'Complete').length;
const complianceScore = totalRequired > 0 ? Math.round((completedRequired / totalRequired) * 100) : 0;

// Create contract value analysis
let contractValue = null;
let contractValueNumeric = null;
if (contractData.paymentTerms && contractData.paymentTerms.amount) {
  contractValue = contractData.paymentTerms.amount;
  // Try to extract numeric value for analysis
  const numericMatch = contractValue.match(/[\d,]+\.?\d*/g);
  if (numericMatch) {
    contractValueNumeric = parseFloat(numericMatch[0].replace(/,/g, ''));
  }
}

// Determine contract risk level based on multiple factors
let riskScore = 0;
const riskFactors = [];

// Factor in compliance score
if (complianceScore < 50) {
  riskScore += 30;
  riskFactors.push('Low compliance score');
} else if (complianceScore < 75) {
  riskScore += 15;
  riskFactors.push('Moderate compliance score');
}

// Factor in missing critical items
if (!contractData.parties || contractData.parties.length < 2) {
  riskScore += 20;
  riskFactors.push('Parties not properly identified');
}

if (!contractData.paymentTerms || !contractData.paymentTerms.amount) {
  riskScore += 15;
  riskFactors.push('Payment terms unclear');
}

if (!contractData.terminationClauses || contractData.terminationClauses.length === 0) {
  riskScore += 10;
  riskFactors.push('No termination clauses');
}

// Factor in expiration
if (daysUntilExpiration !== null && daysUntilExpiration < 30) {
  riskScore += 15;
  riskFactors.push('Contract expiring soon');
}

// Factor in overdue deliverables
if (overdueDeliverables.length > 0) {
  riskScore += 10 * Math.min(overdueDeliverables.length, 3);
  riskFactors.push(`${overdueDeliverables.length} overdue deliverables`);
}

// Determine overall risk level
let overallRiskLevel = 'Low';
if (riskScore >= 50) {
  overallRiskLevel = 'High';
} else if (riskScore >= 25) {
  overallRiskLevel = 'Medium';
}

// Create summary statistics
const summaryStats = {
  totalParties: contractData.parties ? contractData.parties.length : 0,
  totalDeliverables: contractData.deliverables ? contractData.deliverables.length : 0,
  upcomingDeliverables: upcomingDeliverables.length,
  overdueDeliverables: overdueDeliverables.length,
  totalObligations: contractData.obligations ? contractData.obligations.length : 0,
  totalPenalties: contractData.penalties ? contractData.penalties.length : 0,
  totalWarranties: contractData.warranties ? contractData.warranties.length : 0,
  complianceScore: complianceScore,
  riskScore: riskScore,
  overallRiskLevel: overallRiskLevel
};

// Compile final analysis report
const analysisReport = {
  // Contract identification
  contractInfo: {
    title: contractData.contractTitle || 'Untitled Contract',
    type: contractData.contractType || 'Not specified',
    effectiveDate: contractData.effectiveDate || null,
    expirationDate: contractData.expirationDate || null,
    daysUntilExpiration: daysUntilExpiration,
    contractDuration: contractDuration,
    governingLaw: contractData.governingLaw || 'Not specified',
    disputeResolution: contractData.disputeResolution || 'Not specified'
  },

  // Parties information
  parties: contractData.parties || [],

  // Financial terms
  financialTerms: {
    contractValue: contractValue,
    contractValueNumeric: contractValueNumeric,
    paymentSchedule: contractData.paymentTerms?.schedule || 'Not specified',
    currency: contractData.paymentTerms?.currency || 'Not specified',
    lateFees: contractData.paymentTerms?.lateFees || 'Not specified'
  },

  // Deliverables analysis
  deliverables: {
    total: contractData.deliverables ? contractData.deliverables.length : 0,
    upcoming: upcomingDeliverables,
    overdue: overdueDeliverables
  },

  // Obligations by party
  obligations: obligationsByParty,

  // Penalties and warranties
  penalties: contractData.penalties || [],
  warranties: contractData.warranties || [],
  terminationClauses: contractData.terminationClauses || [],

  // Risk assessment
  riskAssessment: {
    aiAnalysis: riskAnalysis,
    calculatedRiskLevel: overallRiskLevel,
    riskScore: riskScore,
    riskFactors: riskFactors
  },

  // Compliance analysis
  compliance: {
    checklist: complianceChecklist,
    score: complianceScore,
    missingCriticalItems: complianceChecklist.filter(item => item.required && item.status === 'Missing').map(item => item.item)
  },

  // Summary
  summary: {
    statistics: summaryStats,
    recommendations: []
  },

  // Metadata
  metadata: {
    analysisDate: new Date().toISOString(),
    analysisVersion: '1.0',
    extractedData: contractData
  }
};

// Add recommendations based on analysis
if (complianceScore < 75) {
  analysisReport.summary.recommendations.push('Complete missing compliance items before contract execution');
}

if (overdueDeliverables.length > 0) {
  analysisReport.summary.recommendations.push('Urgent: Address overdue deliverables immediately');
}

if (daysUntilExpiration !== null && daysUntilExpiration < 60) {
  analysisReport.summary.recommendations.push('Begin contract renewal negotiations');
}

if (!contractData.disputeResolution) {
  analysisReport.summary.recommendations.push('Consider adding dispute resolution clause');
}

if (overallRiskLevel === 'High') {
  analysisReport.summary.recommendations.push('Legal review strongly recommended before proceeding');
}

// Return the analysis report as a single item
return [{ json: analysisReport }];

