// Parse Claude JSON response — hardened with fence stripping, schema validation, safe fallback
const llmItem = $input.first().json;
let llmRaw = llmItem.content?.[0]?.text || llmItem.text || llmItem.message?.content || llmItem.output || llmItem.response || JSON.stringify(llmItem);

// Strip markdown code fences (Claude sometimes wraps JSON)
llmRaw = llmRaw.replace(/```json?\n?/gi, '').replace(/```/g, '').trim();

let parsed = null;
try {
  const start = llmRaw.indexOf('{');
  const end = llmRaw.lastIndexOf('}');
  if (start !== -1 && end !== -1) {
    parsed = JSON.parse(llmRaw.substring(start, end + 1));
  }
} catch (e) {
  console.error('LLM JSON parse failed:', e.message);
}

// Validate required fields
if (parsed) {
  const requiredFields = ['next_stage', 'reply_body'];
  const missing = requiredFields.filter(f => !parsed[f]);
  if (missing.length > 0) {
    console.error('LLM response missing fields:', missing.join(', '));
    parsed = null; // fall through to fallback
  }
  // Validate next_stage is a known value
  const validStages = ['new', 'awaiting_details', 'awaiting_time_confirmation', 'appointment_confirmed', 'opted_out', 'stalled'];
  if (parsed && !validStages.includes(parsed.next_stage)) {
    console.error('LLM returned unknown stage:', parsed.next_stage);
    parsed.next_stage = 'stalled';
  }
}

// Safe fallback if parsing or validation failed
if (!parsed) {
  parsed = {
    next_stage: 'stalled',
    reply_body: 'Thanks for your message. One of the Lidgard Shades team will be in touch with you shortly.\n\nLidgard Shades team',
    confirmed_slot_iso: null,
    is_reschedule: false,
    extracted: {}
  };
}

const prep = $('Prepare LLM Input').first().json;
const inc = $('Extract & Guard').first().json;
const extracted = parsed.extracted || {};

const newHistory = [...(prep.history || [])];
newHistory.push({ role: 'assistant', content: parsed.reply_body, at: new Date().toISOString() });

const existing = prep.existingRow || {};
const existingCalendarEventId = existing.calendar_event_id || '';
const hasExistingEvent = !!existingCalendarEventId;

// Validate confirmed_slot_iso if present
let confirmedSlot = parsed.confirmed_slot_iso || null;
if (confirmedSlot) {
  const dt = new Date(confirmedSlot);
  if (isNaN(dt.getTime()) || dt < new Date()) {
    console.error('Invalid or past appointment time from LLM:', confirmedSlot);
    confirmedSlot = null;
    parsed.next_stage = 'awaiting_time_confirmation'; // re-ask
    parsed.reply_body += '\n\n(Could you confirm which time slot works for you?)';
  }
}

const tableRow = {
  threadId: prep.threadId,
  stage: parsed.next_stage || 'stalled',
  lead_name: extracted.lead_name || existing.lead_name || inc.leadName || '',
  lead_email: inc.leadEmail || existing.lead_email || '',
  blind_type: extracted.blind_type || existing.blind_type || '',
  property_address: extracted.property_address || existing.property_address || '',
  approx_size: extracted.approx_size || existing.approx_size || '',
  preferred_timeframe: extracted.preferred_timeframe || existing.preferred_timeframe || '',
  requested_time: extracted.requested_time || existing.requested_time || '',
  confirmed_time: confirmedSlot || existing.confirmed_time || '',
  calendar_event_id: existingCalendarEventId,
  phone_number: extracted.phone_number || existing.phone_number || '',
  turn_count: prep.turnCount,
  raw_history: JSON.stringify(newHistory),
  last_activity: new Date().toISOString()
};

const isAppointmentConfirmed = parsed.next_stage === 'appointment_confirmed' && !!confirmedSlot;
const isReschedule = !!parsed.is_reschedule || (isAppointmentConfirmed && hasExistingEvent);

return [{
  json: {
    ...inc,
    replyBody: parsed.reply_body,
    nextStage: parsed.next_stage,
    confirmedSlotIso: confirmedSlot,
    extracted,
    tableRow,
    leadName: tableRow.lead_name,
    blindType: tableRow.blind_type,
    propertyAddress: tableRow.property_address,
    approxSize: tableRow.approx_size,
    phoneNumber: tableRow.phone_number,
    isAppointmentConfirmed,
    existingCalendarEventId,
    hasExistingEvent,
    isReschedule
  }
}];

