function getNodeJson(nodeName) {
  return ($node?.[nodeName]?.json) ? $node[nodeName].json : {};
}

function val(obj, key, fallback = "") {
  const v = obj?.[key];
  if (v === null || v === undefined) return fallback;
  return String(v);
}

// Use this for values you insert into text nodes or attributes
function escapeHtml(input) {
  return String(input ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

