// Code node v2 (JavaScript)

const items = $input.all();

async function run() {
  const out = [];

  for (const item of items) {
    const order = item.json;
    const html = order.html || '';

    const buffer = Buffer.from(html, 'utf8');

    // Create binary file called index.html
    const binary = await this.helpers.prepareBinaryData(
      buffer,
      'index.html',   // <-- important: filename that Gotenberg expects
      'text/html'
    );

    out.push({
      json: order,           // keep your order data if you want it later
      binary: {
        htmlFile: binary     // <-- we'll reference this in HTTP node
      }
    });
  }

  return out;
}

return run();

